const checkpoints = [];

function geocodeZip(zip) {
  if (zip === '30301') return { lat: 33.7529, lng: -84.3925 };
  if (zip === '44101') return { lat: 41.4993, lng: -81.6944 };
  return null;
}

function calculateDistanceMiles(lat1, lon1, lat2, lon2) {
  if (typeof lat1 !== 'number' || typeof lon1 !== 'number' || typeof lat2 !== 'number' || typeof lon2 !== 'number') {
    return null;
  }
  const R = 3958.8;
  const toRad = d => d * Math.PI / 180;
  const dLat = toRad(lat2 - lat1);
  const dLon = toRad(lon2 - lon1);
  const a = Math.sin(dLat/2) * Math.sin(dLat/2) +
            Math.cos(toRad(lat1)) * Math.cos(toRad(lat2)) *
            Math.sin(dLon/2) * Math.sin(dLon/2);
  const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1-a));
  return R * c;
}

function isWeekday(day) {
  return ['monday','tuesday','wednesday','thursday','friday'].indexOf(day) !== -1;
}

const opportunities = JSON.parse(localStorage.getItem('volunteer_opportunities') || '[]');
const shifts = JSON.parse(localStorage.getItem('volunteer_shifts') || '[]');
const campuses = JSON.parse(localStorage.getItem('campuses') || '[]');
const regs = JSON.parse(localStorage.getItem('volunteer_shift_registrations') || '[]');

// Compute next month date range based on current system date
const now = new Date();
const year = now.getFullYear();
const month = now.getMonth(); // 0-11
const nextMonth = (month === 11) ? 0 : (month + 1);
const nextYear = (month === 11) ? (year + 1) : year;
const rangeStart = new Date(nextYear, nextMonth, 1);
const rangeEnd = new Date(nextYear, nextMonth + 1, 0); // last day of next month

const searchCoord = geocodeZip('30301');

// Find all qualifying shifts
const qualifyingShifts = shifts.filter(shift => {
  if (!shift || shift.is_cancelled) return false;
  if (!isWeekday(shift.day_of_week)) return false;
  if (shift.time_of_day !== 'evening') return false;
  const start = new Date(shift.start_datetime);
  if (isNaN(start.getTime())) return false;
  const dateOnly = new Date(start.getFullYear(), start.getMonth(), start.getDate());
  if (dateOnly < rangeStart || dateOnly > rangeEnd) return false;
  if (typeof shift.spots_remaining === 'number' && shift.spots_remaining <= 0) return false;

  const opp = opportunities.find(o => o.id === shift.volunteer_opportunity_id);
  if (!opp || !opp.is_active || opp.category !== 'food_pantry') return false;

  const campus = campuses.find(c => c.id === opp.campus_id) || null;
  const lat = (typeof opp.latitude === 'number') ? opp.latitude : (campus && typeof campus.latitude === 'number' ? campus.latitude : null);
  const lng = (typeof opp.longitude === 'number') ? opp.longitude : (campus && typeof campus.longitude === 'number' ? campus.longitude : null);

  if (searchCoord) {
    const dist = calculateDistanceMiles(searchCoord.lat, searchCoord.lng, lat, lng);
    if (dist === null || dist > 5) return false;
  }

  return true;
});

qualifyingShifts.sort((a, b) => {
  const da = new Date(a.start_datetime).getTime();
  const db = new Date(b.start_datetime).getTime();
  if (isNaN(da) && isNaN(db)) return 0;
  if (isNaN(da)) return 1;
  if (isNaN(db)) return -1;
  return da - db;
});

const targetShift = qualifyingShifts.length > 0 ? qualifyingShifts[0] : null;

const regsForTarget = targetShift ? regs.filter(r => r.volunteer_shift_id === targetShift.id) : [];

const hasAnyTargetReg = !!(targetShift && regsForTarget.length > 0);
const hasPersonaReg = !!(targetShift && regsForTarget.some(r => r.email === 'alex@example.com' && r.full_name === 'Alex Rivera'));
const hasPersonaPhone = !!(targetShift && regsForTarget.some(r => r.email === 'alex@example.com' && r.phone === '555-0101'));

// CP1 (0.6): User registered for the earliest qualifying shift (any name/contact)
checkpoints.push({ passed: hasAnyTargetReg, weight: 0.6 });
// CP2 (0.2): Registration uses expected name and email
checkpoints.push({ passed: hasPersonaReg, weight: 0.2 });
// CP3 (0.2): Registration also uses expected phone with that email
checkpoints.push({ passed: hasPersonaPhone, weight: 0.2 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const events = JSON.parse(localStorage.getItem('events') || '[]');
const regs = JSON.parse(localStorage.getItem('event_registrations') || '[]');

// Current month range
const now = new Date();
const year = now.getFullYear();
const month = now.getMonth();
const rangeStart = new Date(year, month, 1);
const rangeEnd = new Date(year, month + 1, 0);

// Find qualifying events
const qualifyingEvents = events.filter(ev => {
  if (!ev || ev.status !== 'scheduled') return false;
  if (ev.category !== 'workshops_classes') return false;
  if (ev.campus_id !== 'downtown_campus') return false;
  if (ev.format !== 'in_person') return false;
  if (ev.cost_type !== 'free') return false;
  if (ev.day_of_week !== 'saturday') return false;
  if (ev.time_of_day !== 'morning') return false;
  if (!ev.title || ev.title.toLowerCase().indexOf('financial') === -1) return false;

  const start = new Date(ev.start_datetime);
  if (isNaN(start.getTime())) return false;
  const dateOnly = new Date(start.getFullYear(), start.getMonth(), start.getDate());
  if (dateOnly < rangeStart || dateOnly > rangeEnd) return false;

  return true;
});

qualifyingEvents.sort((a, b) => {
  const da = new Date(a.start_datetime).getTime();
  const db = new Date(b.start_datetime).getTime();
  if (isNaN(da) && isNaN(db)) return 0;
  if (isNaN(da)) return 1;
  if (isNaN(db)) return -1;
  return da - db;
});

const targetEvent = qualifyingEvents.length > 0 ? qualifyingEvents[0] : null;

const regsForTarget = targetEvent ? regs.filter(r => r.event_id === targetEvent.id) : [];

const hasAnyTargetReg = !!(targetEvent && regsForTarget.length > 0);
const hasCorrectEmail = !!(targetEvent && regsForTarget.some(r => r.email === 'jordan@example.com'));
const hasCorrectNameAndCount = !!(targetEvent && regsForTarget.some(r => {
  const nameMatch = (r.first_name === 'Jordan' && r.last_name === 'Lee') || (r.full_name && r.full_name.indexOf('Jordan') !== -1 && r.full_name.indexOf('Lee') !== -1);
  return nameMatch && (typeof r.num_attendees === 'number' ? r.num_attendees === 1 : true);
}));

// CP1 (0.6): Registered for earliest qualifying event (any details)
checkpoints.push({ passed: hasAnyTargetReg, weight: 0.6 });
// CP2 (0.2): Registration uses expected email
checkpoints.push({ passed: hasCorrectEmail, weight: 0.2 });
// CP3 (0.2): Registration uses expected name and attendee count = 1
checkpoints.push({ passed: hasCorrectNameAndCount, weight: 0.2 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const donations = JSON.parse(localStorage.getItem('donations') || '[]');
const donationAllocations = JSON.parse(localStorage.getItem('donation_allocations') || '[]');
const funds = JSON.parse(localStorage.getItem('funds') || '[]');

const activeFundIds = funds.filter(f => f && f.is_active).map(f => f.id);

function isDonationQualifying(donation) {
  if (!donation) return false;
  if (donation.frequency !== 'one_time') return false;
  if (donation.payment_method !== 'credit_debit_card') return false;
  if (donation.transaction_status !== 'succeeded') return false;

  const allocs = donationAllocations.filter(a => a.donation_id === donation.id && typeof a.amount === 'number' && a.amount > 0);
  if (allocs.length < 2) return false;

  const distinctFundIds = [];
  allocs.forEach(a => {
    if (a.fund_id && distinctFundIds.indexOf(a.fund_id) === -1) {
      distinctFundIds.push(a.fund_id);
    }
  });

  if (distinctFundIds.length < 2) return false;

  const activeDistinct = distinctFundIds.filter(id => activeFundIds.indexOf(id) !== -1);
  if (activeDistinct.length < 2) return false;

  return true;
}

const candidateDonations = donations.filter(d => d && d.frequency === 'one_time' && d.payment_method === 'credit_debit_card' && d.transaction_status === 'succeeded');
const qualifyingDonations = candidateDonations.filter(isDonationQualifying);

let targetDonation = null;
if (qualifyingDonations.length > 0) {
  qualifyingDonations.sort((a, b) => {
    const da = new Date(a.created_at).getTime();
    const db = new Date(b.created_at).getTime();
    if (isNaN(da) && isNaN(db)) return 0;
    if (isNaN(da)) return 1;
    if (isNaN(db)) return -1;
    return da - db;
  });
  targetDonation = qualifyingDonations[qualifyingDonations.length - 1];
}

let exactlyTwoFunds = false;
let cardLooksValid = false;

if (targetDonation) {
  const allocs = donationAllocations.filter(a => a.donation_id === targetDonation.id && typeof a.amount === 'number' && a.amount > 0);
  const distinctFundIds = [];
  allocs.forEach(a => {
    if (a.fund_id && distinctFundIds.indexOf(a.fund_id) === -1) {
      distinctFundIds.push(a.fund_id);
    }
  });
  exactlyTwoFunds = (distinctFundIds.length === 2);

  if (targetDonation.card_number && typeof targetDonation.card_number === 'string') {
    cardLooksValid = targetDonation.card_number.charAt(0) === '4';
  }
}

// CP1 (0.7): At least one qualifying one-time, succeeded card donation split across >=2 different active funds
checkpoints.push({ passed: qualifyingDonations.length > 0, weight: 0.7 });
// CP2 (0.2): Latest qualifying donation allocates to exactly two distinct funds
checkpoints.push({ passed: !!targetDonation && exactlyTwoFunds, weight: 0.2 });
// CP3 (0.1): Card details look like a valid card (starts with '4')
checkpoints.push({ passed: !!targetDonation && cardLooksValid, weight: 0.1 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const plans = JSON.parse(localStorage.getItem('outreach_plans') || '[]');
const items = JSON.parse(localStorage.getItem('outreach_plan_items') || '[]');
const events = JSON.parse(localStorage.getItem('events') || '[]');
const campuses = JSON.parse(localStorage.getItem('campuses') || '[]');

let currentPlanId = localStorage.getItem('currentOutreachPlanId');
if (!currentPlanId && plans.length > 0) {
  currentPlanId = plans[0].id;
}

const now = new Date();
const sixtyDaysMs = 60 * 24 * 60 * 60 * 1000;
const end = new Date(now.getTime() + sixtyDaysMs);

// Collect qualifying events linked in the current plan (unique by event id)
const qualifyingEventMap = {};

items.forEach(item => {
  if (!item || item.outreach_plan_id !== currentPlanId) return;
  const ev = events.find(e => e.id === item.event_id);
  if (!ev) return;
  if (ev.status !== 'scheduled') return;
  if (ev.category !== 'outreach_service') return;
  if (ev.time_of_day !== 'evening') return;

  const start = new Date(ev.start_datetime);
  if (isNaN(start.getTime())) return;
  if (start < now || start > end) return;

  qualifyingEventMap[ev.id] = ev;
});

const qualifyingEvents = Object.keys(qualifyingEventMap).map(id => qualifyingEventMap[id]);

// Count distinct campuses among qualifying events
const campusIdSet = [];
qualifyingEvents.forEach(ev => {
  if (ev.campus_id && campusIdSet.indexOf(ev.campus_id) === -1) {
    campusIdSet.push(ev.campus_id);
  }
});

// Check whether the plan has been viewed (instrumentation)
let viewedRaw = localStorage.getItem('task4_outreachPlanViewed');
let planViewed = false;
if (viewedRaw) {
  try {
    planViewed = JSON.parse(viewedRaw);
  } catch (e) {
    planViewed = (viewedRaw === 'true');
  }
}

// CP1 (0.3): At least 1 qualifying evening outreach event in plan
checkpoints.push({ passed: qualifyingEvents.length >= 1, weight: 0.3 });
// CP2 (0.3): At least 2 qualifying events in plan
checkpoints.push({ passed: qualifyingEvents.length >= 2, weight: 0.3 });
// CP3 (0.3): At least 3 qualifying events with 3 distinct campuses
checkpoints.push({ passed: qualifyingEvents.length >= 3 && campusIdSet.length >= 3, weight: 0.3 });
// CP4 (0.1): User opened/viewed the outreach plan
checkpoints.push({ passed: planViewed === true, weight: 0.1 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const resources = JSON.parse(localStorage.getItem('food_resources') || '[]');
const schedules = JSON.parse(localStorage.getItem('food_resource_schedules') || '[]');
const contacts = JSON.parse(localStorage.getItem('contact_messages') || '[]');

// Find qualifying food pantries (category=food_pantry, has fresh_produce, open Wednesday covering 15:00)
const qualifyingResources = resources.filter(res => {
  if (!res || !res.is_active) return false;
  if (res.category !== 'food_pantry') return false;
  if (!Array.isArray(res.services_offered) || res.services_offered.indexOf('fresh_produce') === -1) return false;

  const resSchedules = schedules.filter(s => s.food_resource_id === res.id);
  if (resSchedules.length === 0) return false;

  const hasWedAfter3 = resSchedules.some(s => {
    if (s.day_of_week !== 'wednesday') return false;
    if (!s.open_time || !s.close_time) return false;
    // afternoon_after_1500 logic: open <= '15:00' && close >= '15:00'
    return (s.open_time <= '15:00' && s.close_time >= '15:00');
  });

  return hasWedAfter3;
});

const qualifyingPhones = qualifyingResources.map(r => r.phone).filter(p => !!p);

// Messages that reference any qualifying pantry phone number
const messagesWithPhone = contacts.filter(cm => {
  if (!cm || !cm.message) return false;
  return qualifyingPhones.some(phone => phone && cm.message.indexOf(phone) !== -1);
});

// Of those, messages that also use the correct subject
const messagesWithCorrectSubject = messagesWithPhone.filter(cm => cm.subject === 'question_about_food_pantry');

// Of those, messages that contain the expected phrase
const phrase = 'more information about this location';
const messagesWithPhrase = messagesWithCorrectSubject.filter(cm => cm.message.toLowerCase().indexOf(phrase) !== -1);

// CP1 (0.5): At least one contact message that includes the phone of a qualifying pantry
checkpoints.push({ passed: messagesWithPhone.length > 0, weight: 0.5 });
// CP2 (0.3): Such a message also uses the 'question_about_food_pantry' subject
checkpoints.push({ passed: messagesWithCorrectSubject.length > 0, weight: 0.3 });
// CP3 (0.2): Such a message explicitly asks for 'more information about this location'
checkpoints.push({ passed: messagesWithPhrase.length > 0, weight: 0.2 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const subs = JSON.parse(localStorage.getItem('devotional_subscriptions') || '[]');

const requiredTopics = ['community_service', 'spiritual_growth'];

function hasRequiredTopics(topics) {
  if (!Array.isArray(topics)) return false;
  return requiredTopics.every(t => topics.indexOf(t) !== -1);
}

const baseSubs = subs.filter(sub => {
  if (!sub) return false;
  if (sub.email_frequency !== 'weekly') return false;
  if (sub.age_group !== 'age_18_35') return false;
  return hasRequiredTopics(sub.topics);
});

const strictSubs = baseSubs.filter(sub => Array.isArray(sub.topics) && sub.topics.length === requiredTopics.length && hasRequiredTopics(sub.topics));
const textOnlySubs = strictSubs.filter(sub => sub.text_only === true);

// CP1 (0.7): At least one subscription with weekly frequency, age 18–35, and including both required topics
checkpoints.push({ passed: baseSubs.length > 0, weight: 0.7 });
// CP2 (0.2): At least one subscription selects only those two topics (no extras)
checkpoints.push({ passed: strictSubs.length > 0, weight: 0.2 });
// CP3 (0.1): At least one strict subscription is marked as text-only
checkpoints.push({ passed: textOnlySubs.length > 0, weight: 0.1 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkointsNameFix = [];
// We'll use 'checkpoints' variable consistently
const checkpoints = checkointsNameFix;

const requests = JSON.parse(localStorage.getItem('prayer_requests') || '[]');

function getNextUpcomingSunday() {
  const today = new Date();
  const day = today.getDay(); // 0=Sunday
  let diff = (7 - day) % 7;
  if (diff === 0) diff = 7; // strictly after today
  const next = new Date(today.getFullYear(), today.getMonth(), today.getDate() + diff);
  const y = next.getFullYear();
  const m = String(next.getMonth() + 1).padStart(2, '0');
  const d = String(next.getDate()).padStart(2, '0');
  return y + '-' + m + '-' + d;
}

const expectedFocusDate = getNextUpcomingSunday() + 'T00:00:00';

const qualifying = requests.filter(pr => {
  if (!pr) return false;
  if (pr.category !== 'family_relationships') return false;
  if (pr.privacy !== 'pastoral_team_only') return false;
  if (pr.focus_date !== expectedFocusDate) return false;
  return true;
});

const withFamilyLanguage = qualifying.filter(pr => pr.message && pr.message.toLowerCase().indexOf('family') !== -1);

// CP1 (0.9): At least one request with Family & Relationships category, pastoral_team_only privacy, and focus date = next Sunday
checkpoints.push({ passed: qualifying.length > 0, weight: 0.9 });
// CP2 (0.1): Qualifying request message explicitly references family
checkpoints.push({ passed: withFamilyLanguage.length > 0, weight: 0.1 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

