const events = JSON.parse(localStorage.getItem('events') || '[]');
const regs = JSON.parse(localStorage.getItem('event_registrations') || '[]');
const campuses = JSON.parse(localStorage.getItem('campuses') || '[]');

// Next month date range
const now = new Date();
const year = now.getFullYear();
const month = now.getMonth();
const nextMonth = (month === 11) ? 0 : (month + 1);
const nextYear = (month === 11) ? (year + 1) : year;
const rangeStart = new Date(nextYear, nextMonth, 1);
const rangeEnd = new Date(nextYear, nextMonth + 1, 0);

const searchCoord = geocodeZip('44101');

const qualifyingEvents = events.filter(ev => {
  if (!ev || ev.status !== 'scheduled') return false;
  if (ev.category !== 'neighborhood_cleanups') return false;
  if (ev.day_of_week !== 'saturday') return false;
  if (ev.time_of_day !== 'morning') return false;
  if (ev.activity_level !== 'light') return false;

  const start = new Date(ev.start_datetime);
  if (isNaN(start.getTime())) return false;
  const dateOnly = new Date(start.getFullYear(), start.getMonth(), start.getDate());
  if (dateOnly < rangeStart || dateOnly > rangeEnd) return false;

  if (searchCoord) {
    const campus = campuses.find(c => c.id === ev.campus_id) || null;
    const lat = (typeof ev.latitude === 'number') ? ev.latitude : (campus && typeof campus.latitude === 'number' ? campus.latitude : null);
    const lng = (typeof ev.longitude === 'number') ? ev.longitude : (campus && typeof campus.longitude === 'number' ? campus.longitude : null);
    const dist = calculateDistanceMiles(searchCoord.lat, searchCoord.lng, lat, lng);
    if (dist === null || dist > 10) return false;
  }

  return true;
