const regsForTarget = targetEvent ? regs.filter(r => r.event_id === targetEvent.id && r.registration_type === 'rsvp') : [];
const regsWithGuests = regsForTarget.filter(r => typeof r.num_attendees === 'number' && r.num_attendees >= 3);
const hasExpectedEmail = !!(targetEvent && regsForTarget.some(r => r.email === 'jamie@example.com'));

// CP1 (0.6): At least one RSVP for the earliest qualifying cleanup (correct event, type=rsvp)
checkpoints.push({ passed: !!(targetEvent && regsForTarget.length > 0), weight: 0.6 });
// CP2 (0.3): RSVP indicates bringing at least two guests (num_attendees >= 3)
checkpoints.push({ passed: regsWithGuests.length > 0, weight: 0.3 });
// CP3 (0.1): RSVP uses the expected email address
checkpoints.push({ passed: hasExpectedEmail, weight: 0.1 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
